import json, re, math

# Get file paths
clinical_path = locals()['var_functions.query_db:48']
expression_path = locals()['var_functions.query_db:44']

# Load data
with open(clinical_path, 'r') as f:
    clinical_data = json.load(f)
with open(expression_path, 'r') as f:
    expression_data = json.load(f)

# Map barcodes to histology
patients = {}
for rec in clinical_data:
    desc = rec['Patient_description']
    hist = rec['histological_type']
    if '[' in hist or ']' in hist: 
        continue
    m = re.search(r'(TCGA-\w+-\w+)', desc)
    if m:
        patients[m.group(1)] = hist

# Map barcodes to IGF2 expression
igf2 = {}
for rec in expression_data:
    igf2[rec['ParticipantBarcode']] = float(rec['normalized_count'])

# Calculate averages by histology
hist_data = {}
for bc, hist in patients.items():
    if bc in igf2:
        val = math.log10(igf2[bc] + 1)
        if hist not in hist_data:
            hist_data[hist] = []
        hist_data[hist].append(val)

# Compute means
result = {}
for hist, vals in hist_data.items():
    result[hist] = round(sum(vals) / len(vals), 4)

# Build answer
lines = []
for hist in sorted(result):
    lines.append(hist + ': ' + str(result[hist]))
answer = '\n'.join(lines)

print('__RESULT__:')
print(answer)

